336	                         sizeof(njs_parser_stack_entry_t));
337	    if (njs_slow_path(entry == NULL)) {
338	        return NJS_ERROR;
339	    }
340	
341	    entry->state = state;
342	    entry->node = node;
343	    entry->optional = is_optional;
344	
